create table dirkspzm32.isi_komm_order (
    sid                   varchar2(2 char) default '01' not null enable,
    firma_nr              number(6, 0) default 1 not null enable,
    komm_id               number(*, 0) not null enable,
    p_komm_id             number(*, 0),
    s_ext_rcv_komm_id     varchar2(30 char),
    s_ext_rcv_info_text   varchar2(255 char),
    s_send_ref_id         varchar2(20 char),
    s_send_tab_name       varchar2(50 char),
    komm_typ              varchar2(10 char) not null enable,
    status                varchar2(10 char) default 'N' not null enable,
    ts                    date default sysdate not null enable,
    prio                  number(*, 5) default 3 not null enable,
    modul_erzeuger        varchar2(10 char) default 'ISI' not null enable,
    modul_bearbeiter      varchar2(10 char) not null enable,
    login_id              number(*, 0),
    bearb_login_id        number(*, 0),
    bearb_arbeitsplatz_id number(*, 0),
    bearb_res_id          number(*, 0),
    bearb_start_datum     date,
    info_text             varchar2(255 char),
    freigabe              varchar2(1 char) default 'M' not null enable,
    freigabe_datum        date,
    freigegeben_login_id  number(*, 0),
    freigegeben_datum     date,
    soll_datum            date,
    fertig_datum          date,
    fertig_login_id       number(*, 0),
    vorgang_id            number(*, 0),
    auf_id                number(*, 0),
    transport_vor_komm    varchar2(1 char) default 'F' not null enable,
    transport_nach_komm   varchar2(1 char) default 'F' not null enable,
    transp_id_vor_komm    number(*, 0),
    transp_id_nach_komm   number(*, 0),
    komm_lgr_platz        varchar2(30 char),
    komm_ziel_lte_id      varchar2(20 char),
    lgr_ort_quelle        number(*, 5),
    lte_id                varchar2(20 char),
    lam_id                number(*, 0),
    artikel_id            number(*, 0) not null enable,
    leitzahl              number(*, 5),
    fa_ag                 number(*, 0),
    fa_upos               number(*, 0),
    charge_id             number(*, 0),
    seriennr_id           number(*, 0),
    mhd                   date,
    menge                 number(*, 3),
    menge_basis           varchar2(3 char),
    mengeneinheit         varchar2(10 char),
    komm_soll_menge       number(*, 3),
    komm_ist_menge        number(*, 3),
    komm_ziel_lgr_platz   varchar2(30 char),
    komm_neu_artikel      varchar2(30 char),
    komm_neu_leitzahl     number(*, 5),
    komm_neu_fa_ag        number(*, 0),
    komm_neu_fa_upos      number(*, 0),
    komm_neu_charge       varchar2(20 char),
    komm_neu_seriennr     varchar2(20 char),
    komm_neu_lhm_name     varchar2(50 char),
    komm_neu_lte_name     varchar2(22 char),
    komm_neu_lte_hoehe    number(*, 3),
    komm_scan_daten_q     varchar2(50 char),
    komm_scan_daten_z     varchar2(50 char),
    anz_lte               number(*, 0),
    lte_lhm_lagen         number(*, 0),
    lte_lhm_pro_lage      number(*, 0),
    lhm_hoehe_lage        number(*, 3),
    packschema_kopf_id    varchar2(20 char),
    lieferschein_nr       varchar2(30 char),
    packschema_traeger_id varchar2(20 char),
    zusatz_etiketten_name varchar2(50 char),
    lte_lhm_lagen_quelle  number(*, 0),
    status_info_text      varchar2(255 char),
    lhm_menge             number(*, 3)
);

alter table dirkspzm32.isi_komm_order
    add constraint chk_komm_order_status
        check ( status in ( 'N', 'FB', 'B', 'TVK', 'TNK',
                            'TVKE', 'TNKE', 'KA', 'KE', 'KEH',
                            'Z' ) ) enable;

alter table dirkspzm32.isi_komm_order
    add constraint chk_komm_typ
        check ( komm_typ in ( 'KE', 'KRE', 'KP', 'LC', 'UP',
                              'UPA', 'W', 'D', 'ZE', 'MV' ) ) enable;

alter table dirkspzm32.isi_komm_order
    add constraint pk_isi_komm_order primary key ( komm_id )
        using index enable;


